var fetchReportList = async () => {
	return (await clientService.get("/api/report_daily/v1.0/list")).data.data;
};
/**
* ņśüņŚģ ņĀÉĻ▓ĆņØ╝ņ¦Ć ņāüņäĖļź╝ ņĪ░ĒÜīĒĢ®ļŗłļŗż.
*/
var fetchReportDetail = async (reportId) => {
	const raw = (await clientService.get(`/api/report_daily/v1.0/${reportId}`)).data.data;
	return {
		reportId: raw.reportId,
		reportDate: raw.reportDate,
		authorSabun: raw.authorSabun,
		authorName: raw.authorName,
		parts: raw.parts.map((p) => ({
			partId: p.partId,
			partNm: p.partNm,
			people: p.people.map((person) => ({
				name: person.personNm,
				inProgress: person.inProgressCnt,
				delayed: person.delayedCnt,
				distributed: person.distributedCnt
			})),
			efficiencyContent: p.efficiencyContent,
			mainInstructionContent: p.mainInstructionContent,
			wasErrorContent: p.wasErrorContent,
			meetingSchedule: p.meetingSchedule,
			specialNotes: p.specialNotes,
			attachments: p.attachments.map((a) => ({
				name: a.realFileName,
				size: a.fileSize,
				seq: a.seq
			}))
		}))
	};
};
/**
* ņśüņŚģ ņĀÉĻ▓ĆņØ╝ņ¦Ćļź╝ ļō▒ļĪØĒĢ®ļŗłļŗż. (ĒīīĒŖĖļ│ä ļé┤ņÜ® + ņ▓©ļČĆĒīīņØ╝ ņØ╝Ļ┤ä ņĀĆņ×ź)
*/
var registerReport = async (reportDate, parts) => {
	const reportData = {
		reportDate,
		parts: parts.map((p) => ({
			partId: p.partId,
			people: p.people.map((person) => ({
				personNm: person.name,
				inProgressCnt: person.inProgress,
				delayedCnt: person.delayed,
				distributedCnt: person.distributed
			})),
			efficiencyContent: p.efficiencyContent,
			mainInstructionContent: p.mainInstructionContent,
			wasErrorContent: p.wasErrorContent,
			meetingSchedule: p.meetingSchedule,
			specialNotes: p.specialNotes
		}))
	};
	const formData = new FormData();
	formData.append("reportData", new Blob([JSON.stringify(reportData)], { type: "application/json" }));
	parts.forEach((p) => {
		p.attachments.forEach((a) => {
			if (a.file) formData.append(`files_${p.partId}`, a.file);
		});
	});
	await clientService.post("/api/report_daily/v1.0/register", formData, { headers: { "Content-Type": "multipart/form-data" } });
};
/**
* ņ▓©ļČĆĒīīņØ╝ņØä ļĖīļØ╝ņÜ░ņĀĆļź╝ ĒåĄĒĢ┤ ņ”ēņŗ£ ļŗżņÜ┤ļĪ£ļō£ĒĢ®ļŗłļŗż.
*/
var downloadAttach = (reportId, partId, seq, realFileName) => {
	const url = `http://localhost:8082/api/report_daily/v1.0/attach/download?reportId=${reportId}&partId=${partId}&seq=${seq}`;
	const link = document.createElement("a");
	link.href = url;
	link.download = realFileName;
	link.click();
};
